insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('perplexity', 'Perplexity', '', '', ARRAY['perplexity','ppl']::text[], 'Core', 'A score for how surprised a model is by text — lower means it saw the words coming.', 'Like a reader finishing your sentences: if they nail every next word, they’re barely surprised; if they keep guessing wrong, they’re baffled.', 'A team compares two language models on the same book; the one with perplexity 12 predicts the text far more comfortably than the one at 45.', '[{"text":"It’s computed from the model’s log probabilities.","id":"logprobability"},{"text":"A fluent-but-wrong model can still score well.","id":"hallucination"}]'::jsonb, 'Perplexity is basically the exponent of the average per-token loss — roughly, the number of equally-likely choices the model felt it was picking between at each step. It’s handy for comparing models on the same data, but it rewards fluency, not truth: a model can be smoothly confident and still wrong.', 'A quick, cheap health check on a model or dataset, but never mistake low perplexity for “correct.”', 'Exp of the mean negative log-likelihood per token; only comparable across models with the same tokenizer and test set.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('logprobability', 'Log probability', 'Log-prob', '', ARRAY['log probability','logprob','log prob','logprobs']::text[], 'Core', 'The model’s confidence in a token, written on a stretched-out scale so tiny odds are easy to handle.', 'Like measuring earthquakes on a log scale — it lets you compare a whisper and a shout without the numbers getting unwieldy.', 'A developer inspects the logprobs and sees the model was 90% sure of “Paris” but split three ways on the next word — a hint it’s unsure.', '[{"text":"Averaged and exponentiated, these give perplexity.","id":"perplexity"},{"text":"The raw scores behind them come from logits.","id":"logits"}]'::jsonb, 'Probabilities multiply and quickly underflow to near-zero, so we work in log space where multiplying becomes adding. Summing token logprobs gives a sequence score; averaging and negating gives the loss that training minimizes and that perplexity is built from.', 'Exposing logprobs lets you flag low-confidence answers instead of shipping every guess as gospel.', 'log(p) of a chosen token under the model’s distribution; summed over a sequence for scoring, negated and averaged for cross-entropy loss.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('beamsearch', 'Beam search', '', '', ARRAY['beam search','beam decoding']::text[], 'Fading', 'A decoding trick that keeps several candidate sentences alive at once and picks the best-scoring whole path.', 'Like planning a road trip by keeping your top few routes open at each junction instead of committing to the first turn that looks good.', 'An older translation system runs beam width 5, exploring five partial translations in parallel before settling on the most probable finished one.', '[{"text":"The simpler one-path cousin.","id":"greedydecoding"},{"text":"What replaced it for open-ended text.","id":"sampling"}]'::jsonb, 'Greedy decoding commits to the single best token each step and can paint itself into a corner; beam search hedges by tracking the k highest-scoring sequences and expanding all of them. It shines in translation and captioning, but for open-ended chat it tends to produce bland, repetitive text, which is why sampling methods largely replaced it.', 'Great when there’s one “right” output like a translation; wrong when you want lively, varied prose.', 'Maintains k partial hypotheses ranked by cumulative log-prob, expanding and pruning to k each step until end tokens fire.', 'Foundations', 30, ARRAY['seed','foundations']::text[]),
  ('repetitionpenalty', 'Repetition penalty', '', '', ARRAY['repetition penalty','repeat penalty']::text[], 'Core', 'A dial that discourages the model from saying the same thing over and over.', 'Like a friend who gently taps you when you tell the same story a third time at dinner.', 'A writer notices the model looping “the results show that…” and nudges the repetition penalty up until the phrasing varies.', '[{"text":"A close relative that penalizes by count.","id":"frequencypenalty"},{"text":"Another that penalizes mere appearance.","id":"presencepenalty"}]'::jsonb, 'It works by shrinking the probability of tokens (or phrases) the model has already produced, so each repeat gets a little harder to choose. Push it too hard and the model avoids necessary repeats — names, code keywords — and the text starts to read strangely, so it’s a balance, not a cure.', 'A fast fix for the “broken record” failure without retraining anything.', 'Divides or subtracts from logits of previously seen tokens before sampling, scaled by a penalty factor.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('frequencypenalty', 'Frequency penalty', '', '', ARRAY['frequency penalty']::text[], 'Core', 'A setting that pushes down a word’s odds the more times it has already appeared.', 'Like a game where each repeat of a word costs you more points than the last.', 'Generating product tags, a dev raises the frequency penalty so common words like “premium” stop dominating every list.', '[{"text":"Penalizes appearance regardless of count.","id":"presencepenalty"},{"text":"The blunter version.","id":"repetitionpenalty"}]'::jsonb, 'Unlike a flat repetition penalty, this one scales with how often a token has shown up — the tenth “the” is barely touched, but the tenth “premium” gets hit hard. It curbs runaway repetition while leaving genuinely common words mostly alone.', 'Tune it to keep outputs varied when you’re generating lists or many short items.', 'Subtracts a term proportional to a token’s prior count in the generation from its logit before softmax.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('presencepenalty', 'Presence penalty', '', '', ARRAY['presence penalty']::text[], 'Core', 'A setting that nudges the model toward new words simply because it hasn’t used them yet.', 'Like a host steering the conversation to guests who haven’t spoken, regardless of how chatty the others were.', 'Brainstorming names, a PM turns up the presence penalty so the model reaches for fresh vocabulary instead of recycling the first three ideas.', '[{"text":"The count-scaled sibling.","id":"frequencypenalty"},{"text":"Both act on the sampling step.","id":"sampling"}]'::jsonb, 'It applies a one-time penalty the moment a token has appeared at all — count doesn’t matter, only presence. That makes it a topic-broadener: it encourages the model to introduce new concepts rather than dwell, which is why it pairs well with brainstorming.', 'Reach for it when you want breadth and novelty rather than tight, on-topic answers.', 'Applies a flat logit reduction to any token that has appeared at least once in the output so far.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('maxtokens', 'Max tokens', '', '', ARRAY['max tokens','max_tokens','max new tokens','max output tokens']::text[], 'Core', 'A hard cap on how many tokens the model is allowed to generate before it must stop.', 'Like a word limit on an essay — hit it and the pen gets taken away mid-sentence if needed.', 'An app sets max tokens to 300 for summaries; a user asks for a full report and the answer cuts off abruptly at the ceiling.', '[{"text":"Counts against the shared budget of the context window.","id":"contextwindow"},{"text":"The other way generation ends.","id":"stopsequence"},{"text":"What gets cut when the cap is hit.","id":"truncation"}]'::jsonb, 'It bounds only the output, not the input, and it’s a budget and safety lever — capping cost and latency. The catch is that the model doesn’t “aim” to finish within it; if the cap is too low the response just truncates mid-thought, so it should be sized to the task.', 'Your main control on cost and response length, but set it too tight and answers get chopped.', 'Upper bound on generated tokens; generation halts at this count or at a stop condition, whichever comes first.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('stopsequence', 'Stop sequence', '', '', ARRAY['stop sequence','stop token','stop string','stop words']::text[], 'Core', 'A bit of text that, once produced, tells the model to stop generating right there.', 'Like a “The End” card that halts the film the instant it appears on screen.', 'A developer sets “\nUser:” as a stop sequence so the model writes the assistant’s reply and doesn’t keep role-playing the user’s next line.', '[{"text":"The blunter length limit.","id":"maxtokens"},{"text":"Defines the boundary of one turn.","id":"turn"}]'::jsonb, 'When the model emits the specified string, decoding halts and the stop text is usually trimmed from the output. It’s how you keep a model from running past its turn or bleeding into the next section of a template — a cleaner boundary than relying on max tokens alone.', 'The tidy way to make responses end where they should instead of rambling on.', 'Decoding terminates when the generated suffix matches any configured stop string; the match is typically stripped.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('truncation', 'Truncation', '', '', ARRAY['truncation','truncate','truncating']::text[], 'Core', 'Chopping text to fit a length limit — usually by dropping whatever spills over the edge.', 'Like trimming a too-long photo to fit the frame; whatever sticks out gets cut off.', 'A long transcript exceeds the context window, so the pipeline truncates the oldest lines, and the model never sees how the meeting began.', '[{"text":"The output limit that forces it.","id":"maxtokens"},{"text":"The input budget it protects.","id":"contextwindow"},{"text":"Its opposite: filling short inputs.","id":"padding"}]'::jsonb, 'Truncation happens on input (to fit the context window) or output (to hit max tokens). The danger is silent information loss: if you cut the wrong end you can lop off the instructions or the crucial early facts, so which side you trim from matters as much as that you trim.', 'A quiet source of “why did it ignore that?” bugs — the model may simply never have seen the cut text.', 'Drops tokens beyond a length budget from a chosen end (left/right) before or after generation.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('padding', 'Padding', '', '', ARRAY['padding','pad token','pad tokens']::text[], 'Core', 'Filler tokens added to short sequences so a batch of them all share the same length.', 'Like adding packing peanuts so every box on the truck is the same size and stacks neatly.', 'To process ten prompts of different lengths at once, the system pads the short ones with a special token until all match the longest.', '[{"text":"What tells the model to ignore the filler.","id":"attentionmask"},{"text":"The opposite operation: cutting to fit.","id":"truncation"}]'::jsonb, 'Hardware wants uniform rectangles, so shorter sequences get pad tokens appended (or prepended). Those tokens carry no meaning and must be hidden from the model’s attention — that’s the attention mask’s job — otherwise the model would “read” the filler as content.', 'Invisible plumbing that makes batching efficient; only surfaces as a bug when the mask is wrong.', 'Appends pad tokens to reach a common sequence length; paired with an attention mask that zeroes them out.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('attentionmask', 'Attention mask', '', '', ARRAY['attention mask','attn mask']::text[], 'Core', 'A yes/no map telling the model which tokens it’s allowed to look at and which to ignore.', 'Like blacking out lines on a page so a reader’s eyes skip them entirely.', 'A padded batch uses an attention mask so the model treats real words as content and the trailing pad tokens as if they weren’t there.', '[{"text":"The filler it usually hides.","id":"padding"},{"text":"Where the masking is applied — inside attention."}]'::jsonb, 'The mask is a set of 1s and 0s applied inside attention: masked positions get their scores driven to negative infinity so they contribute nothing after softmax. Two big uses — hiding padding, and enforcing causality so a token can’t peek at future tokens in a decoder.', 'A silent correctness layer; when it’s misaligned, models produce baffling garbage.', 'Additive/boolean mask over attention logits setting disallowed positions to −inf pre-softmax; used for padding and causal masking.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('tokenlimit', 'Token limit', '', '', ARRAY['token limit','max context','context limit']::text[], 'Core', 'The ceiling on how many tokens a model can handle at once, input and output combined.', 'Like a desk that only fits so many papers — pile on more and the earliest ones slide off.', 'A user pastes a 200-page PDF into a chat with a 128k-token limit and gets an error because the document alone blows past the ceiling.', '[{"text":"The window this limit measures.","id":"contextwindow"},{"text":"What happens on overflow.","id":"truncation"},{"text":"Usable budget shrinks toward the middle.","id":"lostinthemiddle"}]'::jsonb, 'The token limit is the physical size of the context window; prompt, history, and generated reply all draw from the same pool. Exceeding it forces truncation or an error, and even well under it, models often use the far ends of that budget less reliably than the edges.', 'Shapes what you can feed a model in one go and quietly caps how much history a chat can keep.', 'Max total tokens (prompt + completion) the model accepts; overflow triggers truncation or a hard error.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('subword', 'Subword', '', '', ARRAY['subword','subword unit','subword token']::text[], 'Core', 'A chunk of a word — the middle ground between whole words and single letters that models actually read.', 'Like Lego bricks for language: “unhappiness” snaps together from “un,” “happi,” and “ness.”', 'A tokenizer splits “tokenization” into “token” and “ization,” so a rare word still reuses pieces the model already knows.', '[{"text":"The algorithm that finds these units.","id":"bytepairencoding"},{"text":"The process of splitting text this way.","id":"tokenization"}]'::jsonb, 'Whole-word vocabularies balloon and choke on typos and new words; character-level is tiny but makes sequences very long. Subwords are the compromise — common words stay whole, rare ones fragment into familiar parts — which is how models handle words they’ve never literally seen.', 'Why token counts don’t match word counts, and why odd or foreign words cost more.', 'Vocabulary units between characters and words, learned so frequent strings stay intact and rare ones decompose.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('bytepairencoding', 'Byte-pair encoding', 'BPE', '', ARRAY['byte-pair encoding','bpe','byte pair encoding']::text[], 'Core', 'The recipe most tokenizers use to build a vocabulary by repeatedly merging the most common pairs of symbols.', 'Like inventing shorthand: you notice “th” appears constantly, so you give it one squiggle, then merge more from there.', 'Training a tokenizer, BPE starts from raw bytes and merges frequent pairs until “ing” and “tion” become single tokens.', '[{"text":"The units it produces.","id":"subword"},{"text":"The broader process it powers.","id":"tokenization"}]'::jsonb, 'Starting from individual characters or bytes, BPE counts adjacent pairs, merges the most frequent into a new symbol, and repeats thousands of times. The result is a vocabulary where common strings are one token and rare ones split into subwords — a data-driven balance of vocabulary size against sequence length.', 'The unglamorous step that decides your token economics before a model ever runs.', 'Greedy merge algorithm over a corpus that iteratively fuses the highest-frequency adjacent symbol pair into the vocab.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('wordembedding', 'Word embedding', '', '', ARRAY['word embedding','word vector','word2vec','glove']::text[], 'Fading', 'A word turned into a list of numbers so that similar words land near each other in space.', 'Like giving every word a home address in a city where synonyms are neighbors and opposites live across town.', 'A classic model places “king” and “queen” close together, and the gap from “man” to “woman” mirrors the gap from “king” to “queen.”', '[{"text":"The general idea of vector meaning.","id":"embeddings"},{"text":"Whole-sentence version.","id":"sentenceembedding"},{"text":"What replaced fixed vectors.","id":"representation"}]'::jsonb, 'Early methods like word2vec and GloVe gave each word one fixed vector learned from co-occurrence. That was a breakthrough, but the flaw is context-blindness: “bank” gets a single vector whether it’s a river or a vault. Transformers replaced them with context-dependent representations, which is why static word embeddings are fading.', 'Foundational history — mostly superseded by contextual models, but the intuition still explains embeddings.', 'Static, context-independent vectors per token learned from co-occurrence statistics; a precursor to contextual representations.', 'Foundations', 30, ARRAY['seed','foundations']::text[]),
  ('sentenceembedding', 'Sentence embedding', '', '', ARRAY['sentence embedding','sentence vector','text embedding']::text[], 'Core', 'A whole sentence or passage squeezed into a single vector that captures its overall meaning.', 'Like a book’s Dewey number — one code that says roughly what it’s about so you can shelve like with like.', 'A search system embeds every FAQ answer as a vector; a user’s question becomes a vector too, and the nearest ones are the best matches.', '[{"text":"The single-word ancestor.","id":"wordembedding"},{"text":"Where these vectors get stored and searched.","id":"vectordatabase"},{"text":"How they’re compared.","id":"cosinesimilarity"}]'::jsonb, 'Instead of one vector per word, a model pools or specially trains to produce one vector per span. These power semantic search, clustering, and retrieval because closeness in the space means closeness in meaning. Quality hinges on the embedding model — a generic one may miss domain nuance.', 'The workhorse behind semantic search and RAG; picking the right embedding model matters more than people expect.', 'A fixed-length vector for a span, from pooling token states or a purpose-trained encoder, compared via cosine or dot product.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('onehotencoding', 'One-hot encoding', '', '', ARRAY['one-hot encoding','one hot','one-hot','one-hot vector']::text[], 'Core', 'Representing a category as a long row of zeros with a single 1 marking which one it is.', 'Like a row of light switches where exactly one is flipped on to name the choice.', 'With a 50,000-word vocabulary, the word “cat” becomes a vector of 49,999 zeros and one 1 at the “cat” slot.', '[{"text":"The dense upgrade.","id":"embeddings"},{"text":"The dimension that makes it sparse.","id":"vocabulary"}]'::jsonb, 'It’s the simplest way to hand a discrete symbol to math, but it’s sparse and says nothing about similarity — “cat” and “dog” are as far apart as “cat” and “bulldozer.” That limitation is exactly why embeddings exist: they compress one-hot vectors into dense ones where distance carries meaning.', 'Textbook groundwork; it explains why dense embeddings were such a leap.', 'A sparse binary vector of vocab length with one active index; the input that an embedding layer maps to a dense vector.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('softmaxtemperature', 'Softmax temperature', '', '', ARRAY['softmax temperature','temperature scaling']::text[], 'Core', 'The knob inside softmax that flattens or sharpens the model’s probabilities before it picks a word.', 'Like a contrast slider on a photo — turn it up and everything blends together, down and the differences pop.', 'Set high, the model spreads its bets and gets creative; set near zero, it collapses onto the single most likely token almost every time.', '[{"text":"The user-facing setting it implements.","id":"temperature"},{"text":"The function it modifies.","id":"softmax"},{"text":"What spread it changes, measured.","id":"entropy"}]'::jsonb, 'Temperature divides the logits before softmax: values below 1 exaggerate gaps (more deterministic), above 1 shrink them (more random). It’s the mechanism underneath the “temperature” setting you see in APIs — same idea, applied at the point where scores become probabilities.', 'The dial between “safe and repetitive” and “varied and risky” outputs.', 'Scales logits by 1/T before softmax; T→0 approaches argmax, T>1 raises entropy of the distribution.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('entropy', 'Entropy', '', '', ARRAY['entropy','shannon entropy']::text[], 'Core', 'A measure of how spread out and uncertain a set of probabilities is.', 'Like a weather forecast: “50% rain” is high-entropy uncertainty, “99% sunny” is low.', 'When the model’s next-token distribution has high entropy, several words are nearly tied — a sign it’s genuinely unsure what comes next.', '[{"text":"Training’s loss built on top of it.","id":"crossentropy"},{"text":"Temperature raises or lowers it.","id":"softmaxtemperature"}]'::jsonb, 'Entropy is highest when options are evenly likely and zero when one outcome is certain. In language models it quantifies uncertainty at each step, and it’s the theoretical floor that cross-entropy loss measures against — training pushes the model’s predictions to match reality’s true distribution.', 'A principled way to detect “the model is guessing here” and route those cases to a human.', '−Σ p·log p over a distribution; maximal for uniform, zero for a point mass, and the baseline cross-entropy compares to.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('crossentropy', 'Cross-entropy', '', '', ARRAY['cross-entropy','cross entropy','cross-entropy loss']::text[], 'Core', 'The standard scorecard for how far a model’s predicted probabilities are from the true answer.', 'Like grading a weather forecaster not on right/wrong but on how confident they were in what actually happened.', 'During training, the model predicts the next token; cross-entropy is high when it put low probability on the word that actually came next, low when it was confident and correct.', '[{"text":"Its uncertainty baseline.","id":"entropy"},{"text":"Its exponential, for reporting.","id":"perplexity"},{"text":"What it’s computed from.","id":"logprobability"}]'::jsonb, 'Cross-entropy measures the cost of encoding the real data using the model’s predicted distribution — it’s minimized when the two match. It’s the loss almost every language model trains on, it connects directly to perplexity (its exponential), and it rewards putting probability mass on the truth, not just guessing right.', 'The number that goes down as a model learns; the training objective in one word.', '−Σ y·log p between target and predicted distributions; the per-token training loss whose exp is perplexity.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('gradient', 'Gradient', '', '', ARRAY['gradient','gradients']::text[], 'Core', 'The direction and steepness of change that tells each weight which way to move to reduce error.', 'Like feeling the slope under your feet in fog — it tells you which way is downhill even when you can’t see the valley.', 'After a wrong prediction, the gradient for each weight says “nudge me up a little, me down a lot,” and the optimizer follows those hints.', '[{"text":"The corrective signal it carries.","id":"learningsignal"},{"text":"What consumes it to update the model.","id":"training"}]'::jsonb, 'A gradient is the derivative of the loss with respect to every parameter — a giant vector pointing toward steepest increase, so training steps the opposite way. Backpropagation is just the efficient method for computing it, and problems like vanishing or exploding gradients are what make deep networks hard to train.', 'The invisible feedback signal that makes learning possible; when it misbehaves, training stalls.', '∂loss/∂θ for all parameters; computed via backprop and consumed by the optimizer to update weights.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('learningsignal', 'Learning signal', '', '', ARRAY['learning signal','training signal']::text[], 'Core', 'Whatever information tells a model that it was right or wrong and by how much.', 'Like a coach’s feedback after each rep — without it you just repeat the same swing forever.', 'In supervised training the learning signal is the gap to the correct label; in RLHF it’s a reward score standing in for human preference.', '[{"text":"How the signal reaches the weights.","id":"gradient"},{"text":"A signal from human preference.","id":"rlhf"}]'::jsonb, 'Every learning method needs some signal to update on — a label, a reward, a contrastive pair, a reconstruction error. Its quality caps how well the model can do: a noisy, sparse, or biased signal teaches the wrong lesson no matter how big the model. Much of ML progress is really about inventing better signals.', 'Where your data quality actually bites — a clean signal beats a bigger model on a muddy one.', 'The error/reward term driving parameter updates; its density and fidelity bound achievable performance.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('capacity', 'Capacity', '', '', ARRAY['capacity','model capacity']::text[], 'Core', 'How much a model can potentially learn — roughly, how complex a pattern it can represent.', 'Like the size of a suitcase: a bigger one holds more, but an oversized bag half-empty just gets messy and heavy.', 'A tiny model can’t capture the nuance of legal text — too little capacity — while a huge one memorizes the training set instead of generalizing.', '[{"text":"Too much for the data leads here.","id":"overfitting"},{"text":"Too little leads here.","id":"underfitting"},{"text":"The knob that raises it.","id":"parameters"}]'::jsonb, 'Capacity grows with parameters, depth, and width, and it sets the ceiling on complexity a model can fit. Too little and you underfit; too much for your data and you overfit or waste compute. The art is matching capacity to the amount and richness of data, which is exactly what scaling laws try to quantify.', 'Bigger isn’t automatically better — capacity has to be matched to the data and the task.', 'Informal measure of a model’s expressive range, scaling with parameter count, depth, and width.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('emergentability', 'Emergent ability', '', '', ARRAY['emergent ability','emergent abilities','emergent capability']::text[], 'Rising', 'A skill that shows up suddenly only once a model gets big enough, absent in smaller ones.', 'Like water staying liquid, liquid, liquid — then abruptly boiling at 100°C. Nothing, nothing, then a phase change.', 'Small models flunk multi-step arithmetic entirely, then past a certain scale a model starts getting it right, seemingly out of nowhere.', '[{"text":"The parameter growth that triggers it.","id":"capacity"},{"text":"A key one: learning from examples in the prompt.","id":"incontextlearning"}]'::jsonb, 'Emergent abilities are capabilities that don’t improve smoothly with size but appear to switch on past a threshold. They’re real but contested — some “jumps” are artifacts of harsh all-or-nothing metrics, and smoother scoring reveals gradual gains. Either way, they’re why bigger models sometimes surprise their own builders.', 'Why a scale-up can unlock features you didn’t explicitly train for — and why they’re hard to predict.', 'Capabilities that appear near a scale threshold rather than improving continuously; partly metric-dependent.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('incontextlearning', 'In-context learning', 'ICL', '', ARRAY['in-context learning','icl','in context learning']::text[], 'Core', 'A model picking up a new task from examples in the prompt, without any weights changing.', 'Like showing someone three solved puzzles and watching them nail the fourth — no studying, just pattern-matching on the spot.', 'You paste five examples of turning messy addresses into clean ones, then a sixth messy address, and the model formats it correctly.', '[{"text":"Learning from a handful of examples.","id":"fewshot"},{"text":"Doing it with none.","id":"zeroshot"},{"text":"An emergent capability at scale.","id":"emergentability"}]'::jsonb, 'The model’s weights are frozen; it’s inferring the task purely from the pattern in the context and running it during a single forward pass. This is what makes few-shot prompting work and blurs the line between “using” and “teaching” a model — though it’s temporary, lasting only as long as the examples stay in context.', 'Often you can skip fine-tuning entirely — just show examples in the prompt.', 'Task adaptation from prompt demonstrations at inference with no parameter updates; behavior conditioned on context.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('zeroshot', 'Zero-shot', '', '', ARRAY['zero-shot','zero shot','zero-shot learning']::text[], 'Core', 'Asking a model to do a task with no examples at all — just the instruction.', 'Like handing a capable new hire a task described in one sentence and trusting them to figure it out.', '“Classify this review as positive or negative: …” with no sample classifications — the model just does it.', '[{"text":"The same idea with a few examples.","id":"fewshot"},{"text":"With exactly one.","id":"oneshot"},{"text":"The mechanism that makes examples help.","id":"incontextlearning"}]'::jsonb, 'Zero-shot leans entirely on what the model absorbed in pretraining plus your instruction. It’s the cleanest, cheapest way to prompt and often works surprisingly well on common tasks, but for anything unusual or format-sensitive, adding a few examples usually beats it.', 'Try zero-shot first — if it works, you’ve saved tokens and effort; if not, add examples.', 'Task performed from instructions alone with no in-prompt demonstrations, relying on pretrained priors.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('fewshot', 'Few-shot', '', '', ARRAY['few-shot','few shot','few-shot prompting']::text[], 'Core', 'Giving the model a handful of worked examples in the prompt to show it the pattern you want.', 'Like a recipe with a few sample plates photographed — you copy the style for the next dish.', 'Before asking for a product description, you include three examples of the exact tone and length, and the model matches them.', '[{"text":"None-example version.","id":"zeroshot"},{"text":"Single-example version.","id":"oneshot"},{"text":"Why it works without training.","id":"incontextlearning"}]'::jsonb, 'Few-shot prompting supplies several input→output demonstrations so the model infers the task and, crucially, the format. It usually beats zero-shot on tricky or structured tasks, but examples cost tokens and their choice and order can noticeably sway the result — so curation matters.', 'The cheapest reliable quality boost before you consider fine-tuning.', 'Prompting with k demonstrations to steer task and format via in-context learning; sensitive to example selection and order.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('oneshot', 'One-shot', '', '', ARRAY['one-shot','one shot','one-shot prompting']::text[], 'Core', 'Showing the model exactly one example before asking it to do the same thing.', 'Like a single “here’s how” demo before someone tries it themselves.', 'You give one sample of the JSON shape you want, then the real input — and the model mirrors the structure.', '[{"text":"Zero examples.","id":"zeroshot"},{"text":"Several examples.","id":"fewshot"}]'::jsonb, 'One-shot sits between zero-shot and few-shot: a single demonstration is often enough to lock in a format or convention while spending almost no extra tokens. When one example carries the whole pattern, it’s the efficient sweet spot.', 'A great token-cheap way to pin down output format without a full example set.', 'In-context learning with a single demonstration; efficient when one example conveys the target format.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('instructionfollowing', 'Instruction following', '', '', ARRAY['instruction following','instruction-following']::text[], 'Core', 'A model’s ability to actually do what you tell it, not just continue your text.', 'Like the difference between a parrot that echoes you and an assistant that hears “summarize this” and summarizes.', 'You write “Reply in exactly two sentences, no bullet points,” and a well-tuned model obeys both constraints instead of ignoring them.', '[{"text":"The training that instills it.","id":"rlhf"},{"text":"What a raw model does instead.","id":"basemodel"}]'::jsonb, 'Base models just predict likely text; instruction following is a learned behavior, mostly from instruction tuning and RLHF, that makes them treat prompts as commands. It’s never perfect — models miss constraints, especially several at once — which is why clear, checkable instructions still matter.', 'The trait that turns a raw model into something a non-expert can actually direct.', 'Learned behavior (via SFT/RLHF) to condition outputs on directives rather than mere continuation; degrades with constraint count.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('worldmodel', 'World model', '', '', ARRAY['world model','internal model']::text[], 'Rising', 'An internal picture of how things work that lets a system predict what happens next.', 'Like the mental map you use to guess a rolling ball will fall off the table before it does.', 'A model that tracks who’s holding what across a story — and correctly says the key is now in Sara’s pocket — is showing a small world model.', '[{"text":"Tying that model to real facts.","id":"grounding"},{"text":"The internal encodings it would live in.","id":"representation"}]'::jsonb, 'Whether LLMs truly have world models is debated: they clearly build useful internal representations of state and relationships, yet they also make errors no consistent model would. The term matters because robust planning and reasoning arguably require modeling the world, not just predicting surface text.', 'Shorthand for “does it actually understand the situation, or just sound like it?” — the crux of reliability.', 'An internal representation of environment state and dynamics supporting prediction; contested in LLMs.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('grounding', 'Grounding', '', '', ARRAY['grounding','grounded','grounded generation']::text[], 'Core', 'Tying a model’s answers to real, checkable sources instead of letting it free-associate.', 'Like a journalist who cites documents rather than writing “trust me.”', 'A support bot grounded in the actual help docs quotes the real refund window instead of inventing a plausible-sounding one.', '[{"text":"The pattern that supplies the evidence.","id":"rag"},{"text":"What it fights.","id":"hallucination"},{"text":"Knowledge baked into weights, ungrounded.","id":"parametricknowledge"}]'::jsonb, 'Grounding connects generation to external evidence — retrieved documents, tool outputs, databases — so claims can be traced and verified. It’s the main practical defense against hallucination: not because the model gets smarter, but because it’s answering from provided facts rather than parametric memory alone.', 'The difference between a demo and something you’d let talk to customers.', 'Conditioning outputs on retrieved/verified external context and enabling attribution; the core mitigation for hallucination.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('knowledgecutoff', 'Knowledge cutoff', '', '', ARRAY['knowledge cutoff','training cutoff','cutoff date']::text[], 'Core', 'The date after which a model simply hasn’t seen anything — its news stops there.', 'Like a textbook printed last year: thorough up to press time, blank on everything since.', 'Asked who won a championship held after its cutoff, the model either admits it doesn’t know or confidently guesses wrong.', '[{"text":"The frozen knowledge it bounds.","id":"parametricknowledge"},{"text":"How you get around it.","id":"rag"},{"text":"The confident-wrong risk it creates.","id":"hallucination"}]'::jsonb, 'A model’s parametric knowledge is frozen at the end of its training data. Anything later is invisible unless you supply it in the prompt or via retrieval. The subtle danger is that models don’t reliably know what they don’t know, so they can answer post-cutoff questions with unwarranted confidence.', 'Why current-events features need live retrieval bolted on, not just a bigger model.', 'The training-data recency bound of parametric knowledge; post-cutoff facts require in-context grounding.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('parametricknowledge', 'Parametric knowledge', '', '', ARRAY['parametric knowledge','parametric memory']::text[], 'Core', 'What a model “knows” baked into its weights, not looked up from anywhere.', 'Like facts you’ve memorized versus ones you’d Google — parametric knowledge is the stuff already in your head.', 'A model naming the capital of France with no documents provided is drawing on parametric knowledge.', '[{"text":"Its looked-up counterpart.","id":"nonparametricmemory"},{"text":"The date it freezes.","id":"knowledgecutoff"},{"text":"Where the facts live.","id":"weights"}]'::jsonb, 'During training, facts and patterns get compressed into the parameters themselves. It’s fast and always available, but it’s frozen at the knowledge cutoff, can be subtly wrong, and can’t cite a source. That’s the trade-off retrieval addresses by pairing it with non-parametric memory.', 'Convenient but unverifiable — fine for general knowledge, risky for facts that must be current or exact.', 'Information encoded in model weights, accessed without retrieval; static, uncited, cutoff-bound.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('nonparametricmemory', 'Non-parametric memory', '', '', ARRAY['non-parametric memory','nonparametric memory','external memory']::text[], 'Core', 'Knowledge a model pulls in from outside itself at answer time, rather than from its weights.', 'Like an open-book exam — the facts live in the book on your desk, not only in your memory.', 'A RAG system fetches the exact policy paragraph and hands it to the model, so the answer comes from a document, not the weights.', '[{"text":"Its in-the-weights counterpart.","id":"parametricknowledge"},{"text":"The retrieval pattern that uses it.","id":"rag"},{"text":"A common backing store.","id":"vectordatabase"}]'::jsonb, 'Non-parametric memory keeps knowledge in an external, swappable store — documents, a vector database, a tool — that the model reads on demand. Its advantages are updatability and citation: you can change a fact without retraining, and the model can point to where an answer came from. The cost is a retrieval step that can fail.', 'How you keep answers current and auditable without retraining the whole model.', 'Knowledge held in an external store queried at inference; updatable and attributable, unlike weights.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('contextstuffing', 'Context stuffing', '', '', ARRAY['context stuffing','context packing','prompt stuffing']::text[], 'Rising', 'Cramming as much text as possible into the prompt and hoping the model sorts it out.', 'Like dumping every file on your desk in front of a colleague and saying “the answer’s in there somewhere.”', 'Instead of retrieving the right three pages, a team pastes the entire 90-page manual into context — and answers get slower and vaguer.', '[{"text":"The failure it triggers.","id":"lostinthemiddle"},{"text":"The disciplined alternative.","id":"rag"},{"text":"The budget it burns.","id":"tokenlimit"}]'::jsonb, 'Big context windows tempt you to skip retrieval and just include everything. It sometimes works, but it costs tokens, adds latency, and runs into “lost in the middle,” where models attend poorly to material buried between the ends. Curated, relevant context usually beats a firehose.', 'A tempting shortcut that quietly raises cost and lowers quality; selective beats exhaustive.', 'Filling the window with unfiltered content instead of retrieval; degrades via cost, latency, and mid-context attention loss.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('lostinthemiddle', 'Lost in the middle', '', '', ARRAY['lost in the middle','lost-in-the-middle']::text[], 'Rising', 'The tendency of models to notice info at the start and end of a long prompt but overlook the middle.', 'Like remembering the first and last speakers at a long meeting and blanking on everyone in between.', 'A key fact placed on page 20 of a 40-page context gets ignored, while the same fact at the top or bottom gets used.', '[{"text":"Made worse by dumping everything in.","id":"contextstuffing"},{"text":"The stress test for it.","id":"needleinahaystack"},{"text":"Why usable context is less than the max.","id":"effectivecontext"}]'::jsonb, 'Studies find a U-shaped attention pattern: relevant information is used far more reliably when it sits near the edges of the context than when it’s buried in the middle. It means a big context window doesn’t guarantee the model actually reads all of it — placement and retrieval quality still matter.', 'Why “it fits in the window” isn’t the same as “the model will use it”; put the crucial stuff at the edges.', 'Positional recall bias where mid-context tokens are underattended relative to the head and tail.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('needleinahaystack', 'Needle in a haystack', '', '', ARRAY['needle in a haystack','needle in haystack','niah']::text[], 'Rising', 'A test that hides one specific fact in a huge context to see if the model can find it.', 'Like slipping a secret sentence into a long novel and quizzing the reader on it afterward.', 'Evaluators bury “the passcode is 4417” deep in 100k tokens of filler, then ask for the passcode to measure recall by position.', '[{"text":"The weakness it exposes.","id":"lostinthemiddle"},{"text":"What it really measures.","id":"effectivecontext"},{"text":"The broader practice of testing models.","id":"evals"}]'::jsonb, 'The needle-in-a-haystack test probes whether a long context window is truly usable. By varying where the “needle” sits, it maps out weak spots — often the middle — and separates advertised context length from effective context. Passing a simple version doesn’t guarantee handling multiple or reasoning-dependent needles.', 'A quick reality check on long-context claims before you rely on them.', 'Retrieval probe inserting a target fact at varied depths in long context to measure positional recall.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('effectivecontext', 'Effective context', '', '', ARRAY['effective context','effective context length','usable context']::text[], 'Rising', 'How much of a model’s advertised context window it can actually use well, which is usually less.', 'Like a phone plan’s “unlimited” data that quietly throttles after a point — the number on the box isn’t the number you get.', 'A model sold as 128k tokens stays sharp to maybe 32k, then starts missing details buried deeper — its effective context is smaller than its limit.', '[{"text":"The hard ceiling above it.","id":"tokenlimit"},{"text":"Why it’s smaller than the max.","id":"lostinthemiddle"},{"text":"How it’s measured.","id":"needleinahaystack"}]'::jsonb, 'Maximum context length is a hard ceiling; effective context is the practical range where recall and reasoning hold up. Attention biases like lost-in-the-middle mean quality degrades before the ceiling. Needle-in-a-haystack tests are how you estimate it, and it’s often a fraction of the advertised size.', 'Budget for the usable window, not the marketing number, or long-context features will disappoint.', 'The context range over which recall/reasoning stay reliable, typically below the max token limit.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('multimodalinput', 'Multimodal input', '', '', ARRAY['multimodal input','multi-modal input','multimodal']::text[], 'Rising', 'Feeding a model more than just text — images, audio, or video alongside words.', 'Like talking to someone who can both read your note and look at the photo you’re pointing at.', 'You upload a screenshot of an error and type “what’s wrong here?” — the model reads the image and the text together.', '[{"text":"The shared space they’re mapped into.","id":"representation"},{"text":"The budget images strain.","id":"tokenlimit"},{"text":"Vectors as the common currency.","id":"embeddings"}]'::jsonb, 'Multimodal models encode each input type into a shared representation space so the model can reason across them. It unlocks tasks pure text can’t touch — describing images, reading charts, transcribing speech — but each modality adds its own tokenization, cost, and failure modes, and image tokens can eat context fast.', 'Opens whole product categories (photo Q&A, document understanding) but watch the token and latency cost.', 'Inputs of mixed modalities encoded into a shared representation for cross-modal reasoning; images consume many tokens.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('textgeneration', 'Text generation', '', '', ARRAY['text generation','natural language generation','nlg']::text[], 'Core', 'A model producing new text one token at a time, each choice conditioned on everything so far.', 'Like writing a sentence where you commit to one word, then choose the next based on all the words already down.', 'You type a prompt and watch the reply stream in word by word — that streaming is generation happening token by token.', '[{"text":"The step-by-step nature of it.","id":"autoregressive"},{"text":"The prediction at each step.","id":"nexttokenprediction"},{"text":"How each token is chosen.","id":"sampling"}]'::jsonb, 'Generation is autoregressive: the model predicts a probability distribution for the next token, a decoding strategy picks one, it’s appended, and the loop repeats. Everything from temperature to stop sequences is really about shaping or ending this loop. It’s also why longer outputs cost proportionally more time and money.', 'The core act you’re paying for; output length drives both latency and cost linearly.', 'Iterative next-token sampling from the model’s conditional distribution until a stop condition; inherently sequential.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('languagemodel', 'Language model', 'LM', '', ARRAY['language model','lm']::text[], 'Core', 'A system that learns the patterns of language well enough to predict and produce text.', 'Like someone with such a feel for a language that they can finish almost any sentence you start.', 'Give it “The capital of France is” and a language model completes “Paris” because that continuation is overwhelmingly likely.', '[{"text":"The scaled-up version.","id":"llm"},{"text":"The prediction task at its core.","id":"nexttokenprediction"},{"text":"A compact version.","id":"smalllanguagemodel"}]'::jsonb, 'At heart a language model assigns probabilities to sequences of tokens, which lets it both score and generate text. Modern ones are large neural networks trained on huge corpora; “LLM” is just a language model scaled up. The framing matters: it predicts likely text, and likely is not the same as true.', 'The base primitive under every chat product; understanding it as a predictor explains most of its quirks.', 'A model of P(token sequence) trained to predict tokens; scaled up, it becomes an LLM.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('smalllanguagemodel', 'Small language model', 'SLM', '', ARRAY['small language model','slm']::text[], 'Rising', 'A compact language model built to run cheaply and fast, often on your own device.', 'Like a scooter instead of a truck — less hauling power, but nimble, cheap, and it fits in the garage.', 'A phone keyboard runs a small on-device model to suggest words instantly without sending anything to a server.', '[{"text":"The general concept.","id":"languagemodel"},{"text":"How they’re often trained down.","id":"studentmodel"},{"text":"The big models they contrast with.","id":"frontiermodel"}]'::jsonb, 'Small language models trade raw capability for speed, cost, and privacy, and modern training and distillation have made them surprisingly strong on focused tasks. The bet is that most real jobs don’t need a frontier model — a well-tuned small one, running locally, is often good enough and far cheaper.', 'Often the right call for narrow, high-volume, or privacy-sensitive tasks where a giant model is overkill.', 'A parameter-efficient LM optimized for latency, cost, and edge deployment; frequently distilled from a larger teacher.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('mixturemodel', 'Mixture model', '', '', ARRAY['mixture model','mixture of models']::text[], 'Core', 'A model that combines several specialized sub-models, blending their outputs into one answer.', 'Like a panel of specialists where each weighs in and their votes are averaged into a diagnosis.', 'A system routes a coding question to its code-savvy component and a poem request to another, mixing their strengths.', '[{"text":"A group of models voting.","id":"ensemble"},{"text":"Its dense counterpart.","id":"densemodel"},{"text":"The sparse version it enables.","id":"sparsemodel"}]'::jsonb, 'A mixture model composes multiple components, often weighting them by how relevant each is to the input. It’s the statistical idea behind mixture-of-experts architectures, where a router activates only the most relevant sub-networks per token — capturing diverse patterns without one monolithic model doing everything.', 'The concept behind “big model, but only part of it runs per query,” which keeps costs sane at scale.', 'A model combining weighted sub-models; the basis for mixture-of-experts routing over specialized components.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('ensemble', 'Ensemble', '', '', ARRAY['ensemble','ensembling','ensemble model']::text[], 'Core', 'Combining several models’ predictions to get a result better than any one alone.', 'Like “ask the audience” — the crowd’s averaged guess usually beats any single person’s.', 'A team runs three different models on the same input and takes the majority vote, cutting the error rate of each individual model.', '[{"text":"A weighted, learned relative.","id":"mixturemodel"},{"text":"Averaging many best guesses.","id":"sampling"}]'::jsonb, 'Ensembling works because different models make different mistakes, so averaging or voting cancels uncorrelated errors. It reliably boosts accuracy and robustness, but at multiplied compute and latency — you’re running many models instead of one — which is why it’s common in competitions and less so in cost-sensitive production.', 'A dependable accuracy bump you pay for in compute; great for offline scoring, pricey for live serving.', 'Aggregating predictions (vote/average/stack) from diverse models to reduce variance; cost scales with members.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('teachermodel', 'Teacher model', '', '', ARRAY['teacher model']::text[], 'Core', 'A big, capable model whose outputs are used to train a smaller one.', 'Like an expert who writes out worked solutions so an apprentice can learn from them.', 'A large frontier model labels a million examples, and a compact model trains on those labels to imitate it at a fraction of the size.', '[{"text":"The smaller model it trains.","id":"studentmodel"},{"text":"A frequent teacher.","id":"frontiermodel"},{"text":"What small models it produces.","id":"smalllanguagemodel"}]'::jsonb, 'In distillation, the teacher provides targets — final answers or full probability distributions — richer than raw labels, letting the student absorb its behavior. The student can approach the teacher’s quality on many tasks while being far cheaper to run, though it inherits the teacher’s blind spots too.', 'How you get near-frontier quality at small-model cost — with the teacher’s biases along for the ride.', 'The source model in distillation, supplying soft targets or labels the student is trained to match.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('studentmodel', 'Student model', '', '', ARRAY['student model']::text[], 'Core', 'A smaller model trained to imitate a bigger one, keeping much of the skill at a fraction of the cost.', 'Like an apprentice who studies the master’s work and reproduces most of it with far less overhead.', 'A compact chatbot trained on a large model’s answers runs on a single GPU while staying close in quality on everyday requests.', '[{"text":"The model it learns from.","id":"teachermodel"},{"text":"Often the end goal.","id":"smalllanguagemodel"}]'::jsonb, 'The student learns from a teacher’s outputs rather than raw data alone, which packs more signal into fewer examples. Done well, it retains most capability while shrinking dramatically — but it can’t exceed the teacher, and it copies the teacher’s errors and gaps as faithfully as its strengths.', 'The practical path to cheap, fast models that still feel smart on common tasks.', 'The target model in distillation, optimized to match a teacher’s outputs at reduced parameter count.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelcheckpointing', 'Model checkpointing', '', '', ARRAY['model checkpointing','saving checkpoints']::text[], 'Core', 'Saving a snapshot of a model mid-training so you can resume or roll back to it later.', 'Like hitting “save” in a long video game so a crash doesn’t cost you hours of progress.', 'A week-long training run writes a checkpoint every few hours; when a machine fails at hour 50, the team restarts from the latest snapshot.', '[{"text":"A single saved snapshot.","id":"checkpoint"},{"text":"The process it safeguards.","id":"training"},{"text":"Resuming from a saved point.","id":"warmstart"}]'::jsonb, 'Checkpointing periodically persists the weights (and optimizer state) so training runs survive crashes, can be evaluated at intervals, and can be resumed or reverted. It’s essential insurance for expensive runs, and it also lets teams pick the best-performing snapshot rather than whatever happened to be last.', 'The reason a hardware failure during a costly run isn’t a catastrophe.', 'Periodic persistence of weights and optimizer state enabling resume, evaluation, and rollback across a training run.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('warmstart', 'Warm start', '', '', ARRAY['warm start','warm-start']::text[], 'Core', 'Beginning training from an existing model’s weights instead of from scratch.', 'Like starting a novel from a detailed outline rather than a blank page.', 'Rather than train a new model from zero, a team warm-starts from an open-weights checkpoint and fine-tunes on their data.', '[{"text":"The snapshot you start from.","id":"checkpoint"},{"text":"The pretraining that made it.","id":"pretraining"},{"text":"Reusing knowledge across tasks.","id":"basemodel"}]'::jsonb, 'A warm start initializes from pretrained weights so the model already “knows” language and only needs to adapt, saving enormous compute and data versus a cold start. It underpins transfer learning and fine-tuning — but the starting model’s biases and limitations carry over, for better and worse.', 'Why almost nobody trains from scratch anymore — you stand on an existing model’s shoulders.', 'Initializing parameters from a pretrained checkpoint rather than random init to accelerate convergence.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('pretraining', 'Pretraining', 'Pre-training', '', ARRAY['pretraining','pre-training','pretrain']::text[], 'Core', 'The long, expensive first phase where a model learns language from a giant pile of raw text.', 'Like a child soaking up a language for years just by hearing it, before anyone teaches a specific job.', 'A model reads trillions of tokens of web text, books, and code, predicting the next token over and over, until it has a broad feel for language.', '[{"text":"The self-supervised nature of it.","id":"nexttokenprediction"},{"text":"The model it produces.","id":"basemodel"},{"text":"What refines it afterward.","id":"rlhf"},{"text":"Where the knowledge ends up.","id":"parametricknowledge"}]'::jsonb, 'Pretraining is self-supervised: the “labels” are just the next tokens, so no human annotation is needed at this scale. It builds the general capabilities and parametric knowledge everything else builds on, and it’s where most of the compute and cost go. Later stages like fine-tuning and RLHF only steer what pretraining created.', 'The multimillion-dollar foundation you rarely redo; you adapt its result rather than repeat it.', 'Self-supervised next-token training on a massive corpus to learn general representations; the compute-dominant phase.', 'Training', 80, ARRAY['seed','training']::text[]),
  ('rlhf', 'RLHF', 'Reinforcement Learning from Human Feedback', '', ARRAY['rlhf','reinforcement learning from human feedback']::text[], 'Core', 'Teaching a model to behave the way people prefer by turning human ratings into a training signal.', 'Like training a dog with treats — you can’t script every trick, so you reward the behaviors you want and it learns the pattern.', 'Humans rank several model answers best-to-worst; those rankings train a reward model, which then guides the language model toward preferred responses.', '[{"text":"What it refines.","id":"pretraining"},{"text":"The behavior it instills.","id":"instructionfollowing"},{"text":"The preference signal it turns into training.","id":"learningsignal"}]'::jsonb, 'RLHF collects human preference comparisons, fits a reward model to predict them, then uses reinforcement learning to nudge the base model toward high-reward outputs. It’s what turns a raw next-token predictor into a helpful, harmless assistant — but it can be gamed (reward hacking) and inherits the biases of whoever did the rating.', 'The step that makes a model feel aligned and usable; also where your values and rater choices get encoded.', 'Fit a reward model to human preference data, then optimize the policy against it (often PPO) with a KL penalty to the base.', 'Training', 80, ARRAY['seed','training']::text[])
